<?php
 namespace WPAICG\Core\Stream\Vector\BuildContext; use WPAICG\AIPKit_Providers; use WPAICG\Vector\AIPKit_Vector_Store_Manager; use WPAICG\Vector\AIPKit_Vector_Store_Registry; use WP_Error; if (!defined('ABSPATH')) { exit; } function resolve_openai_context_logic( AIPKit_Vector_Store_Manager $vector_store_manager, string $user_message, array $bot_settings, string $main_provider, ?string $frontend_active_openai_vs_id, int $vector_top_k, ?array &$vector_search_scores_output = null ): string { $openai_results = ""; $should_inject_context = ($main_provider !== 'OpenAI'); if (!$should_inject_context) { return ""; } $openai_vector_store_ids_from_settings = $bot_settings['openai_vector_store_ids'] ?? []; $confidence_threshold_percent = (int)($bot_settings['vector_store_confidence_threshold'] ?? 20); $openai_score_threshold = round($confidence_threshold_percent / 100, 4); $final_openai_vector_store_ids = $openai_vector_store_ids_from_settings; if ($frontend_active_openai_vs_id && !in_array($frontend_active_openai_vs_id, $final_openai_vector_store_ids, true)) { $final_openai_vector_store_ids[] = $frontend_active_openai_vs_id; } $final_openai_vector_store_ids = array_unique(array_filter($final_openai_vector_store_ids)); if (!empty($final_openai_vector_store_ids)) { if (!class_exists(AIPKit_Providers::class)) { $providers_path = WPAICG_PLUGIN_DIR . 'classes/dashboard/class-aipkit_providers.php'; if (file_exists($providers_path)) { require_once $providers_path; } else { return ""; } } $openai_api_config = AIPKit_Providers::get_provider_data('OpenAI'); if (!empty($openai_api_config['api_key'])) { $total_results_added = 0; foreach ($final_openai_vector_store_ids as $current_vs_id) { if (empty($current_vs_id)) { continue; } $search_query_vector = [ 'query_text' => $user_message, 'ranking_options' => [ 'score_threshold' => $openai_score_threshold ] ]; $search_results = $vector_store_manager->query_vectors('OpenAI', $current_vs_id, $search_query_vector, $vector_top_k, [], $openai_api_config); if (!is_wp_error($search_results) && !empty($search_results)) { $current_store_results = ""; foreach ($search_results as $item) { if (isset($item['score']) && (float)$item['score'] < $openai_score_threshold) { continue; } if (!empty($item['content'])) { $textContent = is_array($item['content']) ? implode(" ", array_column(array_filter($item['content'], fn ($p) => $p['type'] === 'text'), 'text')) : $item['content']; if (!empty(trim($textContent))) { $total_results_added++; if ($should_inject_context) { $current_store_results .= "- " . trim($textContent) . "\n"; } if ($vector_search_scores_output !== null && isset($item['score'])) { $store_name = $current_vs_id; $openai_stores = AIPKit_Vector_Store_Registry::get_registered_stores_by_provider('OpenAI'); foreach ($openai_stores as $store) { if (isset($store['id']) && $store['id'] === $current_vs_id) { $store_name = $store['name'] ?? $current_vs_id; break; } } $vector_search_scores_output[] = [ 'provider' => 'OpenAI', 'store_id' => $current_vs_id, 'store_name' => $store_name, 'result_id' => $item['id'] ?? null, 'score' => $item['score'], 'content_preview' => wp_trim_words(trim($textContent), 10, '...') ]; } } } } if ($should_inject_context && !empty($current_store_results)) { $store_label = sanitize_text_field($store_name ?? $current_vs_id); $openai_results .= "Context from OpenAI Vector Store ({$store_label}):\n" . $current_store_results . "\n"; } } } } } return $openai_results; } 